export default products
export const getBySubCategory = (sub: string) =>
  products.filter(p => p.subCategory === sub)
export const getBySubCategoryAndFilter = (sub: string, filter: string) =>
  filter === 'all'
    ? products.filter(p => p.subCategory === sub)
    : products.filter(p => p.subCategory === sub && p.filterKey === filter)
export const getFeatured = () => products.filter(p => p.featured)
export const getExclusive = () => products.filter(p => p.isExclusive)
